messageHandlers.script:
p = payload or {}
idx = p.get("index")
if idx is None:
	return
pending = BlueRidge.Common.Util.extractQualifiedValues(self.view.custom.pendingScenarios) or []
self.view.custom.pendingScenarios = [s for s in pending if s.get("index") != idx]
if p.get("outcome") == "failed":
	failed = BlueRidge.Common.Util.extractQualifiedValues(self.view.custom.failedScenarios) or []
	failed.append({"title": p.get("title", ""), "note": ""})
	self.view.custom.failedScenarios = failed
